module priority_encoder_4to2 (anti_a, y);
   input [3:0] anti_a;
   output reg [1:0] y;

   always @(anti_a) begin
      if (anti_a[3])
         y = 2'b11;
      else if (anti_a[2])
         y = 2'b10;
      else if (anti_a[1])
         y = 2'b01;
      else if (anti_a[0])
         y = 2'b00;
      else
         y = 2'b00; // Default case if no input is set
   end
endmodule
